############################################################ # PG Setup Code ############################################################ $var = list_random('a'..'n', 'p'..'z', 'A'..'D', 'F'..'N', 'P'..'T', 'V'..'Z'); Context("Fraction"); $b = Fraction(random_coprime([2..10],[2..10])); Context("Form")->variables->are($var => 'Real'); $given = Formula("-($var + $b)"); Context()->lists->set(AbsoluteValue=>{open=>"(",close=>")"}); Context()->parens->set("("=>{removable=>0,type=>"AbsoluteValue",close=>")"}); $ans = Formula("-$var - $b");
